/// Fold (icmp eq X, C) | (icmp ult Other, (X - C)) -> (icmp ule Other, (X - (C + 1)))
/// Fold (icmp ne X, C) & (icmp uge Other, (X - C)) -> (icmp ugt Other, (X - (C + 1)))
static Value *foldAndOrOfICmpEqConstantAndICmp(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                               bool IsAnd,
                                               InstCombiner::BuilderTy &Builder) {
  // Match (icmp eq/ne X, C) and (icmp pred (add X, -C), Y) or the commuted form.
  // When C=0 the add may be omitted (implicit add X, 0).
  auto Match = [](ICmpInst *CmpA, ICmpInst *CmpB, bool IsAnd,
                  Value *&X, Value *&Y, const APInt *&C,
                  ICmpInst::Predicate &Pred) -> bool {
    // CmpA: icmp eq/ne X, C
    ICmpInst::Predicate EqNePred;
    if (!match(CmpA, m_ICmp(EqNePred, m_Value(X), m_APInt(C))))
      return false;
    bool IsEq = (EqNePred == ICmpInst::ICMP_EQ);
    bool IsNe = (EqNePred == ICmpInst::ICMP_NE);
    if (!IsEq && !IsNe)
      return false;
    if (IsAnd != IsNe)
      return false;

    // CmpB: unsigned icmp with (add X, -C) on one side and Y on the other.
    Value *Op0 = CmpB->getOperand(0), *Op1 = CmpB->getOperand(1);
    Pred = CmpB->getPredicate();
    if (!CmpB->isUnsigned())
      return false;

    // Try to find (add X, -C) or X itself (when C=0) in Op0 or Op1.
    // The add constant must be -C.
    Value *Add = nullptr;
    if (match(Op0, m_Add(m_Specific(X), m_APInt(C)))) {
      // Op0 = add X, K; require K == -C
      if (*C->getValue().get() != -(*C))
        return false;
      Add = Op0;
      Y = Op1;
      return true;
    }
    if (match(Op0, m_Specific(X)) && C->isZero()) {
      // Op0 = X (implicit add X, 0), C must be 0
      Add = Op0;
      Y = Op1;
      return true;
    }
    if (match(Op1, m_Add(m_Specific(X), m_APInt(C))) {
      // Op1 = add X, K; require K == -C
      if (*C->getValue().get() != -(*C))
        return false;
      Add = Op1;
      Y = Op0;
      Pred = ICmpInst::getSwappedPredicate(Pred);
      return true;
    }
    if (match(Op1, m_Specific(X)) && C->isZero()) {
      // Op1 = X (implicit add X, 0), C must be 0
      Add = Op1;
      Y = Op0;
      Pred = ICmpInst::getSwappedPredicate(Pred);
      return true;
    }
    return false;
  };

  Value *X, *Y;
  const APInt *C;
  ICmpInst::Predicate Pred;
  if (Match(Cmp0, Cmp1, IsAnd, X, Y, C, Pred) ||
      Match(Cmp1, Cmp0, IsAnd, X, Y, C, Pred)) {
    // Compute the new predicate.
    // ule -> ult, uge -> ugt, ugt -> uge, ult -> ule
    // i.e., we toggle the "equal" bit in the predicate.
    ICmpInst::Predicate NewPred;
    switch (Pred) {
    case ICmpInst::ICMP_ULE: NewPred = ICmpInst::ICMP_ULT; break;
    case ICmpInst::ICMP_UGE: NewPred = ICmpInst::ICMP_UGT; break;
    case ICmpInst::ICMP_UGT: NewPred = ICmpInst::ICMP_UGE; break;
    case ICmpInst::ICMP_ULT: NewPred = ICmpInst::ICMP_ULE; break;
    default: return nullptr;
    }

    // Compute the new add constant: K - 1 = -C - 1 = -(C+1)
    APInt NewC = -(*C) - 1;
    Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(X->getType(), NewC));
    return Builder.CreateICmp(NewPred, NewAdd, Y);
  }
  return nullptr;
}
